import{c as e,Q as a,j as i,m as t}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"CLI Agents Part 2: Claude Code Best Practices","description":"","frontmatter":{"url":"https://vld-bc.com/blog/cli-agents-part2-claude-code-best-practices","title":"CLI Agents Part 2: Claude Code Best Practices","type":"article"},"headers":[],"relativePath":"research/ai-articles/18-vld-bc-cli-agents-best-practices.md","filePath":"research/ai-articles/18-vld-bc-cli-agents-best-practices.md","lastUpdated":1779796674000}'),r={name:"research/ai-articles/18-vld-bc-cli-agents-best-practices.md"};function s(o,l,c,n,d,p){return a(),i("div",null,[...l[0]||(l[0]=[t('<h1 id="cli-agents-part-2-claude-code-best-practices" tabindex="-1">CLI Agents Part 2: Claude Code Best Practices <a class="header-anchor" href="#cli-agents-part-2-claude-code-best-practices" aria-label="Permalink to &quot;CLI Agents Part 2: Claude Code Best Practices&quot;">​</a></h1><p><strong>原始 URL</strong>: <a href="https://vld-bc.com/blog/cli-agents-part2-claude-code-best-practices" target="_blank" rel="noreferrer">https://vld-bc.com/blog/cli-agents-part2-claude-code-best-practices</a></p><p><strong>作者</strong>: Volodymyr Dvernytskyi<br><strong>來源</strong>: 關於 Navision &amp; Dynamics 365 Business Central 的部落格</p><hr><h2 id="核心摘要" tabindex="-1">核心摘要 <a class="header-anchor" href="#核心摘要" aria-label="Permalink to &quot;核心摘要&quot;">​</a></h2><p>Volodymyr Dvernytskyi 提供了關於如何有效配置 Claude Code 的實踐指導，涵蓋配置檔案、上下文管理、代理委派、自訂命令和集成協議。本文強調了結構化配置優於臨時性提示的重要性，以及如何通過 CLAUDE.md、權限模式和上下文管理來建立可靠的 AI 代理工作流。</p><p>核心論點：<strong>配置優於對話</strong>。將重複指令和專案規則集中在配置檔案，而不是在每次交互中重述，可顯著提高效率並減少令牌消耗。</p><h3 id="六大關鍵實踐" tabindex="-1">六大關鍵實踐 <a class="header-anchor" href="#六大關鍵實踐" aria-label="Permalink to &quot;六大關鍵實踐&quot;">​</a></h3><ol><li><p><strong>CLAUDE.md 配置</strong></p><ul><li>專案特定配置的基礎</li><li>包含：構建和測試指令、代碼風格規則、架構邊界、專案慣例</li><li>使用「優先 X 而非 Y」的正向措辭，優於「不要做 Z」的負向措辭</li><li>支持多層級結構（全局、專案、組件層級）</li></ul></li><li><p><strong>權限模式</strong></p><ul><li>Default（提示確認）</li><li>Accept Edits（自動批准編輯）</li><li>Plan（唯讀分析）</li><li>Don&#39;t Ask（預設拒絕，需明確許可）</li><li>Bypass Permissions（完全存取，限隔離環境）</li></ul></li><li><p><strong>上下文管理</strong></p><ul><li>「上下文即 AI 代理在單一對話會話中看到和記憶的所有內容」</li><li>平衡充分資訊與認知過載</li><li>使用 <code>/compact</code> 和 <code>/context</code> 命令監控令牌消耗</li><li>接近上限時開始新對話</li></ul></li><li><p><strong>Subagents（子代理）</strong></p><ul><li>專門的 Claude 實例處理聚焦子任務</li><li>隔離的上下文視窗、權限、工具存取和模型選擇</li><li>實例：專用測試運行器、代碼審查者、文件生成器</li></ul></li><li><p><strong>自訂命令</strong></p><ul><li>Markdown 檔案存儲的斜線命令，自動化重複任務</li><li>示例：<code>/al-status</code> 摘要 Git 變更並生成 PR 描述</li></ul></li><li><p><strong>MCP 集成</strong></p><ul><li>模型上下文協議連接啟用外部集成</li><li>示例：Playwright MCP 用於瀏覽器自動化測試和驗證工作流</li></ul></li></ol><hr><h2 id="關鍵實踐" tabindex="-1">關鍵實踐 <a class="header-anchor" href="#關鍵實踐" aria-label="Permalink to &quot;關鍵實踐&quot;">​</a></h2><h3 id="積極的措辭策略" tabindex="-1">積極的措辭策略 <a class="header-anchor" href="#積極的措辭策略" aria-label="Permalink to &quot;積極的措辭策略&quot;">​</a></h3><p>使用「Prefer X over Y」而非「Never do Z」，讓 AI 更容易理解和遵循偏好。</p><h3 id="上下文監控檢查清單" tabindex="-1">上下文監控檢查清單 <a class="header-anchor" href="#上下文監控檢查清單" aria-label="Permalink to &quot;上下文監控檢查清單&quot;">​</a></h3><ul><li>[ ] 確認每次對話的起點上下文大小</li><li>[ ] 定期用 <code>/context</code> 診斷實際消耗來源</li><li>[ ] 早期（狀態「健康」時）主動使用 <code>/compact</code></li><li>[ ] 避免在警告出現時才進行壓縮</li></ul><h3 id="al-語言最佳實踐-business-central-特定" tabindex="-1">AL 語言最佳實踐（Business Central 特定） <a class="header-anchor" href="#al-語言最佳實踐-business-central-特定" aria-label="Permalink to &quot;AL 語言最佳實踐（Business Central 特定）&quot;">​</a></h3><ul><li>物件設計和命名慣例</li><li>性能最佳化策略</li><li>事務處理和錯誤管理</li><li>全面測試策略</li></ul><hr><h2 id="關鍵引用與數據" tabindex="-1">關鍵引用與數據 <a class="header-anchor" href="#關鍵引用與數據" aria-label="Permalink to &quot;關鍵引用與數據&quot;">​</a></h2><blockquote><p>「我們的角色作為軟體工程師變得不那麼關注技術細節，更多是提供良好的護欄讓代理完成工作」</p></blockquote><blockquote><p>「配置檔案是 AI 代理的憲法」</p></blockquote><p><strong>上下文成本示例</strong>：</p><ul><li>CLAUDE.md（100 行）: ~500-800 tokens</li><li>標準工具載入: ~1000-1500 tokens</li><li>子代理開銷: ~200-300 tokens（每個）</li><li>完整對話歷史: 線性增長</li></ul><p><strong>權限模式選擇</strong>：</p><ul><li>開發環境: Bypass Permissions</li><li>CI/CD: Accept Edits（受限範圍）</li><li>生產部署: Plan → 手動審批 → 執行</li></ul><hr><h2 id="實踐適用性" tabindex="-1">實踐適用性 <a class="header-anchor" href="#實踐適用性" aria-label="Permalink to &quot;實踐適用性&quot;">​</a></h2><p>此方法論適用於：</p><ul><li>多人協作的中大型專案</li><li>需要一致性的重複性任務</li><li>需要嚴格審查的關鍵系統</li><li>長期維護的代碼庫</li></ul><p>配置驅動的方法確保一致性、可追蹤性和長期可維護性，特別適合在團隊層級應用 Claude Code。</p>',30)])])}const b=e(r,[["render",s]]);export{h as __pageData,b as default};
